import React from "react"

import Layout from "../components/layout"
import SEO from "../components/seo"

import Nav from "../components/nav"
import Float from "../components/float"

import PersonalData from "../components/resume/PersonalData"
import Contact from "../components/resume/Contact"
import Qualification from "../components/resume/Qualification"
import Hobby from "../components/resume/Hobby"
import Certification from "../components/resume/Certification"
import Education from "../components/resume/Education"
import TargetJob from "../components/resume/TargetJob"
// import Language from "../components/resume/Language"
import Website from "../components/resume/Website"
import Tool from "../components/resume/Tool"

class IndexPage extends React.Component {
  state = {
    language: "th",
    nav: false,
  }

  componentDidMount = () => {
    window.addEventListener("scroll", this.handleScroll)
  }

  componentWillUnmount = () => {
    window.removeEventListener("scroll", this.handleScroll)
  }

  handleScroll = () => {
    if (window.scrollY > 230) {
      this.setState({ nav: true })
    } else {
      this.setState({ nav: false })
    }
  }

  changeLang = lang => {
    this.setState({ language: lang })
  }

  render() {
    return (
      <Layout>
        <SEO title="Home" />
        {/* nav */}
        <Nav changeLang={this.changeLang} />
        {/* layout */}
        <div className="columns is-centered">
          <div className="column is-6">
            <PersonalData lang={this.state.language} />
          </div>
        </div>

        <div className="columns is-centered">
          <div className="column is-5">
            <div>
              <Contact lang={this.state.language} />
            </div>
            <div style={{ marginTop: "1.25rem" }}>
              <Qualification lang={this.state.language} />
            </div>
            <div style={{ marginTop: "1.25rem" }}>
              <Hobby lang={this.state.language} />
            </div>
            <div style={{ marginTop: "1.25rem" }}>
              <Certification lang={this.state.language} />
            </div>
          </div>
          <div className="column is-5">
            <div>
              <Education lang={this.state.language} />
            </div>
            <div style={{ marginTop: "1.25rem" }}>
              <TargetJob lang={this.state.language} />
            </div>
          </div>
        </div>

        <div className="column" style={{ marginBottom: "3rem" }}>
          <Tool lang={this.state.language} />
        </div>

        <div className="column">
          <Website />
        </div>

        {/* <div className="columns is-centered">
          <div className="column is-9">
            <Language lang={this.state.language} />
          </div>
        </div> */}

        {/* float */}
        <Float nav={this.state.nav} changeLang={this.changeLang} />
      </Layout>
    )
  }
}

export default IndexPage
