import React from "react"
import { StaticQuery, graphql } from "gatsby"
import Img from "gatsby-image"

/*
 * This component is built using `gatsby-image` to automatically serve optimized
 * images with lazy loading and reduced file sizes. The image is loaded using a
 * `StaticQuery`, which allows us to load the image from directly within this
 * component, rather than having to pass the image data down from pages.
 *
 * For more information, see the docs:
 * - `gatsby-image`: https://gatsby.dev/gatsby-image
 * - `StaticQuery`: https://gatsby.dev/staticquery
 */

const Image = ({ base, isRounded = false, hovered = false }) => (
  <StaticQuery
    query={graphql`
      query {
        allFile {
          nodes {
            base
            childImageSharp {
              fluid(maxWidth: 400) {
                ...GatsbyImageSharpFluid
              }
            }
          }
        }
      }
    `}
    render={data => {
      const file = data.allFile.nodes.find(item => item.base === base)
      if (file === undefined) {
        console.log("base do not match image")
        return null
      }

      return (
        <Img
          className={hovered ? "animated pulse infinite" : ""}
          style={isRounded ? { borderRadius: "50%" } : {}}
          fluid={file.childImageSharp.fluid}
        />
      )
    }}
  />
)
export default Image
